INSERT INTO public.kb_articles (
  issue_code, product, sub_product, category, issue_type, title, slug,
  question_variants, short_summary, possible_reasons, what_to_check,
  resolution_steps, documents_required, resolution_timeline,
  when_to_raise_ticket, internal_escalation_note,
  status, published_at, visibility, owner_team, escalation_level
)
SELECT
  a.ic, a.prod, a.sp, a.cat, a.it, a.ttl,
  lower(a.ic),
  string_to_array(a.qv, ','),
  a.ss,
  p.pr, p.wtc, p.rs,
  string_to_array(p.dr, '; '),
  p.rt,
  'If unresolved beyond expected timeline, repeats, or involves money stuck/incorrect debit/credit. Mention Issue Code ' || a.ic || '.',
  'Escalate to L2 immediately if financial impact or compliance risk is suspected.',
  'published'::content_status, now(), 'public', 'support', 1
FROM articles a
JOIN patterns p ON p.pk = a.ppk;
